def longest_subarray_k_distinct(nums, k):
    """
    Find longest subarray with EXACTLY k distinct elements where every
    distinct element appears the same number of times (count = c).

    Key insight: a window [l..r] with exactly k distinct elements is valid
    iff its length == k * max_count (i.e., all counts equal max_count = c).

    O(n^2/k) average case — for each left anchor l, the inner loop breaks
    as soon as a (k+1)-th distinct element appears, which happens quickly
    for arrays with many distinct values.
    """
    if not nums or k <= 0:
        return 0

    n = len(nums)
    best = 0

    for l in range(n):
        count = {}
        distinct = 0
        max_count = 0

        for r in range(l, n):
            v = nums[r]
            if v not in count:
                distinct += 1
            count[v] = count.get(v, 0) + 1
            if count[v] > max_count:
                max_count = count[v]

            if distinct > k:
                break  # can never become valid by adding more elements

            if distinct == k:
                length = r - l + 1
                # Valid iff all k elements have count = max_count
                if length == k * max_count and length > best:
                    best = length

    return best

