def min_jumps(nums):
    n = len(nums)
    if n == 1:
        return 0

    jumps = 0
    current_end = 0  # farthest index reachable with 'jumps' jumps
    farthest = 0     # farthest index reachable with 'jumps+1' jumps

    for i in range(n - 1):
        farthest = max(farthest, i + nums[i])
        if farthest >= n - 1:
            return jumps + 1
        if i == current_end:
            # Must make a jump; if we can't advance, it's impossible
            if farthest <= i:
                return -1
            jumps += 1
            current_end = farthest

    return -1

